import axios from "axios";
class LoginService {
  login = async ({
    emailId,
    password,
  }: {
    emailId: string;
    password: string;
  }) => {
    try {
      const response = await axios.post(
        "http://localhost:4444/auth/login",
        {
          emailId,
          password,
        },
        {
          withCredentials: true,
        }
      );
      return response;
    } catch (error) {
      console.error("Error during signup:", error);
      throw error;
    }
  };

  getUser = async () => {
    try {
      const response = await axios.get("http://localhost:4444/profile/view", {
        withCredentials: true,
      });
      return response;
    } catch (error) {
      console.error("Error during signup:", error);
      throw error;
    }
  };
}

export const loginService = new LoginService();
